import React, { useState, useEffect } from 'react';
import { salesAPI, productsAPI, deliveriesAPI } from '../services/api';

function Dashboard() {
  const [dashboardData, setDashboardData] = useState(null);
  const [recentSales, setRecentSales] = useState([]);
  const [products, setProducts] = useState([]);
  const [upcomingDeliveries, setUpcomingDeliveries] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      const [dashboardRes, salesRes, productsRes, deliveriesRes] = await Promise.all([
        salesAPI.getDashboard().catch(() => ({ data: null })),
        salesAPI.getAll().catch(() => ({ data: [] })),
        productsAPI.getAll().catch(() => ({ data: [] })),
        deliveriesAPI.getAll().catch(() => ({ data: [] })),
      ]);

      setDashboardData(dashboardRes.data);
      setRecentSales(salesRes.data?.slice(0, 5) || []);
      setProducts(productsRes.data?.slice(0, 5) || []);
      setUpcomingDeliveries(deliveriesRes.data?.slice(0, 5) || []);
      setError(null);
    } catch (err) {
      setError('Failed to load dashboard data');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(amount || 0);
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  if (error) {
    return <div className="error">{error}</div>;
  }

  return (
    <div>
      <div className="page-header">
        <h1>Dashboard</h1>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <h3>Today's Sales</h3>
          <div className="value">{formatCurrency(dashboardData?.today_sales)}</div>
        </div>
        <div className="stat-card">
          <h3>This Week</h3>
          <div className="value">{formatCurrency(dashboardData?.week_sales)}</div>
        </div>
        <div className="stat-card">
          <h3>This Month</h3>
          <div className="value">{formatCurrency(dashboardData?.month_sales)}</div>
        </div>
        <div className="stat-card">
          <h3>Total Products</h3>
          <div className="value">{dashboardData?.total_products || 0}</div>
        </div>
        <div className="stat-card">
          <h3>Pending Deliveries</h3>
          <div className="value">{dashboardData?.pending_deliveries || 0}</div>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        <div className="card">
          <h3>Recent Sales</h3>
          {recentSales.length === 0 ? (
            <p className="empty-state">No recent sales</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Date</th>
                  <th>Items</th>
                  <th>Total</th>
                </tr>
              </thead>
              <tbody>
                {recentSales.map((sale) => (
                  <tr key={sale.id}>
                    <td>#{sale.id}</td>
                    <td>{formatDate(sale.created_at)}</td>
                    <td>{sale.items?.length || 0}</td>
                    <td>{formatCurrency(sale.total_amount)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

        <div className="card">
          <h3>Top Products</h3>
          {products.length === 0 ? (
            <p className="empty-state">No products found</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Product</th>
                  <th>Price</th>
                  <th>Stock</th>
                </tr>
              </thead>
              <tbody>
                {products.map((product) => (
                  <tr key={product.id}>
                    <td>{product.name}</td>
                    <td>{formatCurrency(product.price)}</td>
                    <td>{product.stock_quantity}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

        <div className="card">
          <h3>Upcoming Deliveries</h3>
          {upcomingDeliveries.length === 0 ? (
            <p className="empty-state">No upcoming deliveries</p>
          ) : (
            <div className="delivery-list">
              {upcomingDeliveries.map((delivery) => (
                <div key={delivery.id} className="delivery-item">
                  <h4>{delivery.customer_name}</h4>
                  <p>Address: {delivery.address}</p>
                  <p>Status: {delivery.status}</p>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="card">
          <h3>Quick Stats</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
            <div style={{ textAlign: 'center', padding: '20px', background: '#f8f9fa', borderRadius: '8px' }}>
              <h4 style={{ marginBottom: '10px' }}>Low Stock Items</h4>
              <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#e74c3c' }}>
                {dashboardData?.low_stock_count || 0}
              </div>
            </div>
            <div style={{ textAlign: 'center', padding: '20px', background: '#f8f9fa', borderRadius: '8px' }}>
              <h4 style={{ marginBottom: '10px' }}>Completed Today</h4>
              <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#27ae60' }}>
                {dashboardData?.completed_today || 0}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
